3	
4	describe("MHPCO Claim Office", () => {
5	  describe("quote - basic functionality", () => {
6	    it("should return 0 premium for empty item list", () => {
7	      expect(quote([])).toBe(0);
8	    });
9	    it("should return 100G base premium for single sword", () => {
10	      expect(quote([{ type: "sword" }])).toBe(100);
11	    });
