1	export interface Item {
2	  type: "sword" | "amulet" | "staff" | "potion" | "component";
3	  count?: number;
4	}
5	
6	export interface Policy {
7	  id: string;
8	  premiumSum: number;
9	}
10	
11	const itemBasePremiums: Record<Item["type"], number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  component: 25,
17	};
18	
19	const getComponentPremium = (count: number | undefined): number => {
20	  return count === 3 ? 35 : 25;
21	};
22	
23	const getItemPremium = (item: Item): number => {
24	  if (item.type === "component") {
25	    return getComponentPremium(item.count);
26	  }
27	  return itemBasePremiums[item.type];
28	};
29	
30	const policies: Map<string, Policy> = new Map();
31	const CLAIM_DEDUCTIBLE = 100;
32	
33	export function quote(items: Item[]): number {
34	  return items.reduce((total, item) => total + getItemPremium(item), 0);
35	}
36	
37	export function createPolicy(items: Item[]): Policy {
38	  const id = Math.random().toString(36).substring(2, 11);
39	  const premiumSum = quote(items);
40	  const policy: Policy = { id, premiumSum };
41	  policies.set(id, policy);
42	  return policy;
43	}
44	
45	export function claim(
46	  policyId: string,
47	  damage: number
48	): { policyId: string; payout: number; error: string } {
49	  const policy = policies.get(policyId);
50	  if (!policy) {
51	    return {
52	      policyId,
53	      payout: 0,
54	      error: "Policy not found",
55	    };
56	  }
57	  const payout = Math.max(0, damage - CLAIM_DEDUCTIBLE);
58	  return {
59	    policyId,
60	    payout,
61	    error: "",
62	  };
63	}
